import React from "react";

import styles from "./DottedHaloCard.module.css";

export interface DottedHaloCardProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  title?: React.ReactNode;
  bodyClassName?: string;
  patternInset?: string;
  patternSize?: string;
  patternDotSize?: string;
}

export function DottedHaloCard({
  title,
  children,
  className = "",
  bodyClassName = "",
  patternInset,
  patternSize,
  patternDotSize,
  style,
  ...props
}: DottedHaloCardProps) {
  return (
    <div
      className={`${styles.root} ${className}`.trim()}
      style={
        {
          "--dotted-halo-inset": patternInset,
          "--dotted-halo-pattern-size": patternSize,
          "--dotted-halo-dot-size": patternDotSize,
          ...style,
        } as React.CSSProperties
      }
      {...props}
    >
      {title ? <h3 className={styles.title}>{title}</h3> : null}
      <div className={`${styles.body} ${bodyClassName}`.trim()}>{children}</div>
    </div>
  );
}

export default DottedHaloCard;

.root {
  position: relative;
  z-index: 0;
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
  padding: 1.5rem 2rem;
  border: 1px solid var(--text-primary);
  border-radius: 1rem;
  background: var(--bg-primary);
  color: var(--text-primary);
}

.root::before {
  content: "";
  position: absolute;
  z-index: -1;
  inset: calc(var(--dotted-halo-inset, 1.35rem) * -1);
  border-radius: calc(1rem + var(--dotted-halo-inset, 1.35rem));
  background-image: radial-gradient(
    color-mix(in srgb, var(--text-primary) 76%, transparent)
      var(--dotted-halo-dot-size, 1px),
    transparent 0
  );
  background-position: center;
  background-repeat: repeat;
  background-size: var(--dotted-halo-pattern-size, 5px)
    var(--dotted-halo-pattern-size, 5px);
  opacity: 0.7;
}

.title {
  margin: 0;
  font-family: var(--font-mono);
  font-size: 1rem;
  font-weight: 600;
  line-height: 1.3;
}

.body {
  color: var(--text-secondary);
  line-height: 1.7;
}
